# loaders/raman_loader.pyimport tkinter as tkfrom tkinter import filedialogimport osimport matplotlib.pyplot as pltimport spcimport ramanspydef select_directory():    root = tk.Tk()    root.withdraw()  # Hide the main window    root.attributes('-topmost', True)  # Bring dialog to the front    directory = filedialog.askdirectory(title="Select Raman Spectra Directory")    root.destroy()    return directorydef select_file():    root = tk.Tk()    root.withdraw()  # Hide the main window    root.attributes('-topmost', True)  # Bring dialog to the front    file_path = filedialog.askopenfilename(title="Select GCMS Data File", filetypes=[("Excel files", "*.xlsx")])    root.destroy()    return file_pathdef load_raman(directory, spectra_dir):    """   Loads Raman spectra from .spc files in the specified directory, saves individual and overlaid raw spectra plots,   and returns a dictionary of spectra grouped by sample name.   Parameters:       directory (str): Path to the directory containing raw raman .spc files.       spectra_dir (str): Path to the directory where raw spectra plots will be saved.   Returns:       sample_spectra (dict): Dictionary where keys are sample names (sample_name) and values are raman spectra (ramanspy object).       shifts (np.ndarray): Raman shift values (x-axis).   """    sample_spectra = {}  # Dictionary to store sampleID and corresponding spectra     shifts = None    # Define a colormap or a list of colors for the sample groups    colors = plt.cm.tab10.colors  # Using a colormap with 10 distinct colors    sample_group_colors = {}  # Dictionary to map sample groups to colors    for filename in os.listdir(directory):        if filename.endswith(".spc"):             raman_path = os.path.join(directory, filename)                    #sample_group = filename.split('-')[0]   # Extract sample group (e.g., 1-1, 1-2, 1-3 → "1")            sample_name = filename.split('_')[0]    # Get sample name                    raw = spc.File(raman_path)  # Load the SPC file            if len(raw.sub) > 0:                shifts = raw.x  # Store x-values (Raman shift) if not already set            spectral_data = raw.sub[0].y  # Extract intensity (y) values            spectrum = ramanspy.Spectrum(spectral_data, shifts)                    # Plot and save the individual raw spectrum            plt.figure(figsize=(8, 5))            plt.plot(spectrum.spectral_axis, spectrum.spectral_data, label=sample_name, color="blue")            plt.title(f"Raw Spectrum: {sample_name}")            plt.xlabel("Raman Shift (cm⁻¹)")            plt.ylabel("Intensity")            individual_plot_path = os.path.join(spectra_dir, f"{sample_name}_Raw.png")            plt.savefig(individual_plot_path, dpi=300, bbox_inches="tight")            plt.close()                             # Add sample_name : spectrum to dictionary sample_spectra            if sample_name not in sample_spectra:  # Check if the sample name is already in the dictionary                sample_spectra[sample_name] = []  # Initialize an empty list for the sample name if it doesn't exist            sample_spectra[sample_name].append(spectrum)  # Append the spectrum to the list corresponding to the sample name        #Generate and Save Overlay PLot    plt.figure(figsize=(8, 5))    for sample_name, spectra in sample_spectra.items():                sample_group = sample_name.split('-')[0]  # Extract sample group from sample name        if sample_group not in sample_group_colors:           sample_group_colors[sample_group] = colors[len(sample_group_colors) % len(colors)]  # Assign a color to the sample group                for spectrum in spectra:            plt.plot(                spectrum.spectral_axis,                 spectrum.spectral_data,                 label=sample_group,                  color=sample_group_colors[sample_group])    plt.title("Overlay of Raw Spectra")    plt.xlabel("Raman Shift (cm⁻¹)")    plt.ylabel("Intensity")    plt.legend(loc="best", ncol=2, fontsize="small")  # Adjust legend to avoid clutter    plt.savefig(os.path.join(spectra_dir, "Overlay_Raw.png"), dpi=300, bbox_inches="tight")    plt.close()        return sample_spectra, shifts   